.nav-goto-input::placeholder{color:var(--dim)}
.nav-goto-btn{font-family:'DM Mono',monospace;font-size:.75rem;letter-spacing:.08em;text-transform:uppercase;cursor:pointer;padding:.2rem .4rem}
